function replayLogoAnimation(){var a=document.getElementById("logo-container");if(!a||!a.parentNode)return;var b=a.parentNode,c=a.cloneNode(!0);b.removeChild(a);window.requestAnimationFrame(function(){b.appendChild(c)})}function isHistoryNavigationEvent(a){return!!(a&&a.persisted)||(window.performance&&window.performance.getEntriesByType&&window.performance.getEntriesByType("navigation").length&&window.performance.getEntriesByType("navigation")[0].type==="back_forward")}window.addEventListener("pageshow",function(a){isHistoryNavigationEvent(a)&&setTimeout(replayLogoAnimation,0)});function newpage(){window.location=newLocation}$(".fade-out").click(function(a){a.preventDefault(),newLocation=this.href,$("body").fadeOut("slow",newpage)});